import { expect, test } from '@playwright/test';
import { loadSample, uploadFixture, waitForTimeline } from './helpers.js';

test.describe('Session Viewing', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    await loadSample(page, 'Claude Code');
  });

  test.describe('Timeline rendering', () => {
    test('displays user messages with the user label', async ({ page }) => {
      const userLabel = page.locator('main span:has-text("user")').first();
      await expect(userLabel).toBeVisible();
    });

    test('displays assistant messages with the assistant label', async ({
      page,
    }) => {
      const agentLabel = page.locator('main span:has-text("agent")').first();
      await expect(agentLabel).toBeVisible();
    });

    test('displays tool call entries with the tool name', async ({ page }) => {
      const toolCall = page.locator('main').getByText('tool_call').first();
      await expect(toolCall).toBeVisible();
    });

    test('shows tool call results when expanded', async ({ page }) => {
      const toolCallButton = page
        .locator('main button')
        .filter({ hasText: 'tool_call' })
        .first();
      await toolCallButton.click();

      await expect(
        page.locator('main').getByText('output').first()
      ).toBeVisible();
    });

    test('shows thinking/reasoning toggle on assistant messages when present', async ({
      page,
    }) => {
      // The Claude Code sample includes thinking blocks.
      // Look for the "// thinking" or "// encrypted reasoning" toggle button.
      const thinkingButton = page
        .locator('main button')
        .filter({ hasText: /thinking|reasoning/ })
        .first();
      // The sample may or may not have thinking blocks, so verify conditionally
      const isVisible = await thinkingButton.isVisible().catch(() => false);
      if (isVisible) {
        await expect(thinkingButton).toBeVisible();
      } else {
        // If no thinking blocks in sample, the test is not applicable — skip gracefully
        // by verifying the timeline at least renders correctly
        await expect(
          page.locator('main').getByText('agent').first()
        ).toBeVisible();
      }
    });
  });

  test.describe('Subagent visualization', () => {
    test('displays subagent entries in the main timeline', async ({ page }) => {
      const subagentEntry = page.locator('main').getByText('subagent').first();
      await expect(subagentEntry).toBeVisible();
    });

    test('opens a subagent panel when a subagent entry is clicked and expanded', async ({
      page,
    }) => {
      const subagentButton = page
        .locator('main button')
        .filter({ hasText: 'subagent' })
        .first();
      await subagentButton.click();

      const openButton = page.getByText('open conversation').first();
      if (await openButton.isVisible()) {
        await openButton.click();
        await expect(page.getByText('[close]')).toBeVisible();
      }
    });

    test('shows the subagent nested timeline in the panel', async ({
      page,
    }) => {
      const subagentButton = page
        .locator('main button')
        .filter({ hasText: 'subagent' })
        .first();
      await subagentButton.click();

      const openButton = page.getByText('open conversation').first();
      if (await openButton.isVisible()) {
        await openButton.click();
        // The subagent panel should show timeline entries (user/agent labels)
        const subagentPanel = page.locator('main .overflow-y-auto').last();
        await expect(subagentPanel).toBeVisible();
      }
    });

    test('shows the subagent description or type in the panel divider bar', async ({
      page,
    }) => {
      const subagentButton = page
        .locator('main button')
        .filter({ hasText: 'subagent' })
        .first();
      await subagentButton.click();

      const openButton = page.getByText('open conversation').first();
      if (await openButton.isVisible()) {
        await openButton.click();
        // The divider bar should show "subagent" label
        const dividerBar = page.locator('div.border-y.border-accent\\/30');
        await expect(dividerBar.getByText('subagent')).toBeVisible();
      }
    });

    test('closes the subagent panel when the [close] button is clicked', async ({
      page,
    }) => {
      const subagentButton = page
        .locator('main button')
        .filter({ hasText: 'subagent' })
        .first();
      await subagentButton.click();

      const openButton = page.getByText('open conversation').first();
      if (await openButton.isVisible()) {
        await openButton.click();
        await expect(page.getByText('[close]')).toBeVisible();

        await page.getByText('[close]').click();
        await expect(page.getByText('[close]')).not.toBeVisible();
      }
    });
  });

  test.describe('System messages', () => {
    test('displays system messages in the timeline when present', async ({
      page,
    }) => {
      const systemEntry = page
        .locator('main button:has-text("// system")')
        .first();
      if (await systemEntry.isVisible()) {
        await expect(systemEntry).toBeVisible();
      }
    });
  });
});

